import { createAgent } from "flue";
import { agentBrowser } from "../tools/website-qa/agent-browser.js";
import { writeWebsiteQaReport } from "../tools/website-qa/write-qa-report.js";

export default createAgent({
  name: "website-qa",
  instructions:
    "Run browser-driven QA on a website or web app. Use agent-browser to navigate, inspect, interact with onboarding/signup flows, capture screenshots, and then write a concise Markdown QA report.",
  tools: [agentBrowser, writeWebsiteQaReport]
});

import { spawn } from "node:child_process";

export interface AgentBrowserInput {
  args: string[];
  sessionName?: string;
  allowedDomains?: string[];
  maxOutputChars?: number;
}

export interface AgentBrowserResult {
  ok: boolean;
  command: string[];
  stdout: string;
  stderr: string;
  exitCode: number | null;
}

export async function runAgentBrowser(input: AgentBrowserInput): Promise<AgentBrowserResult> {
  const command = process.env.AGENT_BROWSER_BIN ?? "agent-browser";
  const args = [
    ...(input.sessionName ? ["--session-name", input.sessionName] : []),
    ...input.args,
  ];
  const result = await run(command, args, {
    AGENT_BROWSER_ALLOWED_DOMAINS: input.allowedDomains?.join(","),
    AGENT_BROWSER_CONTENT_BOUNDARIES: "1",
  });
  const max = input.maxOutputChars ?? 12000;

  return {
    ...result,
    stdout: result.stdout.slice(0, max),
    stderr: result.stderr.slice(0, max),
  };
}

async function run(command: string, args: string[], env: Record<string, string | undefined>): Promise<AgentBrowserResult> {
  return new Promise((resolve) => {
    const child = spawn(command, args, {
      env: { ...process.env, ...withoutUndefined(env) },
      stdio: ["ignore", "pipe", "pipe"],
    });
    let stdout = "";
    let stderr = "";

    child.stdout.on("data", (chunk) => {
      stdout += String(chunk);
    });
    child.stderr.on("data", (chunk) => {
      stderr += String(chunk);
    });
    child.on("error", (error) => {
      resolve({
        ok: false,
        command: [command, ...args],
        stdout,
        stderr: error.message,
        exitCode: null,
      });
    });
    child.on("close", (code) => {
      resolve({
        ok: code === 0,
        command: [command, ...args],
        stdout,
        stderr,
        exitCode: code,
      });
    });
  });
}

function withoutUndefined(values: Record<string, string | undefined>): Record<string, string> {
  return Object.fromEntries(Object.entries(values).filter((entry): entry is [string, string] => entry[1] !== undefined));
}

import { mkdir, writeFile } from "node:fs/promises";
import path from "node:path";

export interface QaReportInput {
  targetUrl: string;
  result: "passed" | "blocked" | "failed" | "incomplete";
  summary: string;
  checked: string[];
  findings: string[];
  evidence: string[];
  nextActions: string[];
  reportPath?: string;
}

export async function writeQaReport(input: QaReportInput) {
  const reportPath = input.reportPath ?? defaultReportPath(input.targetUrl);
  const report = renderQaReport(input);
  await mkdir(path.dirname(reportPath), { recursive: true });
  await writeFile(reportPath, report, "utf8");

  return {
    reportPath,
    report,
  };
}

function renderQaReport(input: QaReportInput): string {
  return `# Website QA Report

Target: ${input.targetUrl}
Checked: ${new Date().toISOString()}
Result: ${input.result}

## Summary

${input.summary}

## What Was Checked

${list(input.checked)}

## Findings

${list(input.findings)}

## Evidence

${list(input.evidence)}

## Recommended Next Actions

${list(input.nextActions)}
`;
}

function list(items: string[]): string {
  return items.length ? items.map((item) => `- ${item}`).join("\n") : "- None";
}

function defaultReportPath(url: string): string {
  const safe = url.replace(/^https?:\/\//i, "").replace(/[^a-z0-9]+/gi, "-").replace(/^-|-$/g, "").toLowerCase();
  return `reports/${safe || "website"}-${new Date().toISOString().slice(0, 10)}.md`;
}

import { runAgentBrowser, type AgentBrowserInput } from "../../lib/agents/website-qa/browser.js";

export async function agentBrowser(input: AgentBrowserInput) {
  return runAgentBrowser(input);
}

import { writeQaReport, type QaReportInput } from "../../lib/agents/website-qa/report.js";

export async function writeWebsiteQaReport(input: QaReportInput) {
  return writeQaReport(input);
}
